pub enum VcsServerKind {
    BitBucketServer(BitBucketServer),
    BitbucketStandaloneServer(BitbucketStandaloneServer),
    GitHubServer(GitHubServer),
    GitLabServer(GitLabServer),
    GiteaServer(GiteaServer),
    GogsServer(GogsServer),
    JenkinsServer(JenkinsServer),
    SpaceServer(SpaceServer),
    TeamcityServer(TeamcityServer),
    VcsHostingServer(VcsHostingServer),
    VcsServer(VcsServerData),
}

#[derive(Serialize, Deserialize, Debug, Clone, Default, PartialEq)]
pub struct VcsServerData {
    #[serde(skip_serializing_if = "Option::is_none")]
    pub id: Option<String>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub url: Option<String>,
}

impl VcsServer {
    pub fn id(&self) -> Option<&str> {
        match self {
            Self::Known(k) => k.id(),
            Self::Unknown(_) => None,
        }
    }
    pub fn url(&self) -> Option<&str> {
        match self {
            Self::Known(k) => k.url(),
            Self::Unknown(_) => None,
        }
    }
}

impl VcsServerKind {
    pub fn id(&self) -> Option<&str> {
        match self {
            Self::BitBucketServer(x) => x.id.as_deref(),
            Self::BitbucketStandaloneServer(x) => x.id.as_deref(),
            Self::GitHubServer(x) => x.id.as_deref(),
            Self::GitLabServer(x) => x.id.as_deref(),
            Self::GiteaServer(x) => x.id.as_deref(),
            Self::GogsServer(x) => x.id.as_deref(),
            Self::JenkinsServer(x) => x.id.as_deref(),
            Self::SpaceServer(x) => x.id.as_deref(),
            Self::TeamcityServer(x) => x.id.as_deref(),
            Self::VcsHostingServer(x) => x.id.as_deref(),
            Self::VcsServer(x) => x.id.as_deref(),
        }
    }
    pub fn url(&self) -> Option<&str> {
        match self {
            Self::BitBucketServer(x) => x.url.as_deref(),
            Self::BitbucketStandaloneServer(x) => x.url.as_deref(),
            Self::GitHubServer(x) => x.url.as_deref(),
            Self::GitLabServer(x) => x.url.as_deref(),
            Self::GiteaServer(x) => x.url.as_deref(),
            Self::GogsServer(x) => x.url.as_deref(),
            Self::JenkinsServer(x) => x.url.as_deref(),
            Self::SpaceServer(x) => x.url.as_deref(),
            Self::TeamcityServer(x) => x.url.as_deref(),
            Self::VcsHostingServer(x) => x.url.as_deref(),
            Self::VcsServer(x) => x.url.as_deref(),
        }
    }
}
